<template>
  <div id="myCesium">
    <div class="header">
      <p class="title">
        激光网路管理
      </p>
    </div>
    <div id="cesiumContainer" />
    <div id="loadingOverlay">
      <h1>Loading...</h1>
    </div>
    <div class="tabContainer">
      <ul class="tabs">
        <li
          v-for="(item, index) in tabs"
          :key="index"
          class="tab"
          :class="tabIndex === index ? 'active' : ''"
          @click="changeTab(index)"
        >
          {{ item }}
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
import * as Cesium from 'cesium'
import { DateTimeFormatter, JulianDateToTimestamp, TimeFormatter, degreesFromCartesian } from '@/utils/tools.js'
import { twoline2satrec, propagate, gstime, eciToGeodetic, degreesLong, degreesLat } from 'satellite.js'
import LineFlowMaterialProperty from '@/utils/lineFlowMaterialProperty.js'

// 配置Cesium的Worker路径
Cesium.WorkerPath = '/cesium-vue-demo/Cesium/Workers/'

let viewer
// 天地图个人token
const myMapToken = 'd4d540f219a11d3a7ce9d09ab072b10c'
// 当前时间可固定时间可取当前时间
const time = new Date(2024, 1, 2, 12, 0, 0)
let max = time.getTime()
const nowTime = time.getTime()
// 毫秒数
let day = 1000 * 60 * 60 * 24
// 间隔
let interval = 1000 * 10
let min = max - day
console.log('时间戳=>', nowTime)
// 快进倍数
let multiplier = 60
// 存储卫星通信线路信息
let showFlyObject = {}
// 存储地面通信线路信息
const showGroundObject = {}
// 存储卫星信息
let satelliteObj = {}
// 存储卫星数据
let satellites = new Cesium.CustomDataSource('satellite')
// 存储卫星线路数据
let polylines = new Cesium.CustomDataSource('statelliteLine')
// 存储雷达数据
let radars = new Cesium.CustomDataSource('radar')
// 存储卫星通信连接数据
let connection = new Cesium.CustomDataSource('connection')
// 卫星模型
let satellitesModelMap = {
  'LEO': 'models/satellite.glb'
}
let radarsModelMap = {
  'radar': 'models/radar.glb',
  'radar2': 'models/radar2.glb',
  'ykCenter': 'models/ykCenter.glb'
}
// 通信线路材质
let polylineMaterialMap = {
  'default': new Cesium.Color(1.0, 1.0, 1.0, 1),
  'success': new Cesium.Color(0.0, 1.0, 0.0, 1),
  'warning': new Cesium.Color(1.0, 1.0, 0.0, 1),
  'error': new Cesium.Color(1.0, 0.0, 0.0, 1)
}
// 通信状态
let connectionStateMap = {
  'default': '无业务时线路通达',
  'success': '有业务流、业务流正常',
  'warning': '有业务流、质量差',
  'error': '有业务流、线路断'
}
// 存储雷达点位数据
let radarPoints = []

export default {
  name: 'HomeView',
  data () {
    return {
      tabs: ['高轨', '倾斜轨', '近地轨'],
      tabIndex: 1,
      viewer: null,
      handler: null
    }
  },
  mounted () {
    this.init()
  },
  destroyed () {
    this.destroyCesiumViewer()
  },
  methods: {
    // 销毁cesium
    destroyCesiumViewer () {
      if (viewer) {
        viewer.destroy()
        viewer = null
      }
      console.log('Cesium viewer destroyed')
    },
    init () {
      // Cesium.Ion Token
      Cesium.Ion.defaultAccessToken = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJqdGkiOiJiMzI4N2MwNC0zOTlmLTRlYzktODk1YS05NmY3ZDljZjM4ZDYiLCJpZCI6MjA0NTQyLCJpYXQiOjE3MTE0NDM2OTB9.Utv7Dq1s7-N7eH7sBaHmWArJuihYB8aJl9YPSndjdwY'
      // 配置Cesium的Worker路径
      Cesium.WorkerPath = '/Cesium/Workers/'
      viewer = new Cesium.Viewer('cesiumContainer', {
        homeButton: true, // 可以回到最初的视角
        sceneModePicker: false, // 地球的展示形式，球体还是平面
        baseLayerPicker: false, // 底图影像切换
        animation: true, // 是否显示动画控件
        infoBox: true, // 是否显示点击要素之后显示的信息
        selectionIndicator: true, // 要素选中框
        geocoder: false, // 是否显示地名查找控件
        timeline: true, // 是否显示时间线控件
        fullscreenButton: true, // 是否显示全屏按钮
        shouldAnimate: true, // 是否需要动画
        navigationHelpButton: false // 是否显示帮助信息控件
      })
      viewer._cesiumWidget._creditContainer.style.display = 'none' // 隐藏logo
      viewer.scene.skyBox.show = true // 是否显示星空
      viewer.scene.backgroundColor = Cesium.Color.BLACK // 地球背景颜色
      viewer.scene.sun.show = true // 是否显示太阳
      viewer.scene.moon.show = true // 是否显示有月亮
      viewer.scene.skyAtmosphere.show = true // 是否隐藏大气圈
      viewer.scene.globe.show = true // 是否显示地球
      // viewer.scene.globe.enableLighting = true;//true：360度地球有亮和黑的区分，亮和黑的影像地图亮度是一样的
      // viewer.extend(Cesium.viewerCesiumInspectorMixin); //调试和检查功能
      viewer.scene.postProcessStages.fxaa.enabled = true // 开启抗锯齿
      viewer.scene.globe.depthTestAgainstTerrain = false // 开启深度检测
      viewer.scene.globe.tileLoadProgressEvent.addEventListener(function () {
        if (viewer.scene.globe.tilesLoaded) {
          // 加载完成后隐藏覆盖层
          document.getElementById('loadingOverlay').style.display = 'none'
        }
      })
      // 取消默认的左键双击事件
      // viewer.cesiumWidget.screenSpaceEventHandler.removeInputAction(
      //   Cesium.ScreenSpaceEventType.LEFT_DOUBLE_CLICK
      // )
      // 格式化时间
      viewer.animation.viewModel.dateFormatter = DateTimeFormatter
      viewer.animation.viewModel.timeFormatter = TimeFormatter
      viewer.timeline.makeLabel = DateTimeFormatter
      // 天地图 叠加路网与注记矢量
      viewer.imageryLayers.addImageryProvider(new Cesium.WebMapTileServiceImageryProvider({
        url: `http://t0.tianditu.gov.cn/cia_w/wmts?tk=${myMapToken}`,
        layer: 'cia',
        style: 'default',
        tileMatrixSetID: 'w',
        format: 'tiles',
        maximumLevel: 18
      }))

      // 设置摄像机视图
      viewer.scene.camera.setView({
        destination: new Cesium.Cartesian3.fromDegrees(
          116.4074,
          0.9042,
          this.tabIndex === 0 ? 120000000 : 25000000
        ),
        orientation: {}
      })

      // 重写主页按钮行为
      viewer.homeButton.viewModel.command.beforeExecute.addEventListener((e) => {
        e.cancel = true
        // 你要飞的位置
        viewer.camera.flyTo(
          {
            destination: new Cesium.Cartesian3.fromDegrees(
              116.4074,
              0.9042,
              this.tabIndex === 0 ? 120000000 : 25000000
            ),
            orientation: {}
          },
          500
        )
      })
      // 加载视图
      this.onViewerLoaded(viewer, this.tabIndex)
    },
    // 视图加载并设置事件监听器
    onViewerLoaded (Viewer, tabIndex) {
      viewer = Viewer
      this.handler = new Cesium.ScreenSpaceEventHandler(viewer.canvas)
      this.setTimeline()
      this.loadSatelliteData(`satellite${tabIndex}`)
      this.loadRadarData()
      this.left_click()
      this.right_click()
      viewer.clock.onTick.addEventListener(() => {
        this.computeSatelliteToRadarRange()
        this.computeSatellitesRange()
        this.computeRadarsRange()
      })
    },
    /**
       * @description: 初始化Cesium地球时钟,改为东八区时间，使其在指定的日期和时间范围内循环播放
       * @return {*}
       */
    setTimeline () {
      let startTime = Cesium.JulianDate.fromDate(new Date(min))
      let stopTime = Cesium.JulianDate.fromDate(new Date(max))
      viewer.clock.startTime = startTime.clone()
      viewer.clock.stopTime = stopTime.clone()
      viewer.clock.currentTime = stopTime.clone()
      viewer.clock.clockRange = Cesium.ClockRange.LOOP_STOP
      viewer.clock.multiplier = multiplier
      viewer.timeline.zoomTo(startTime, stopTime)
    },

    /**
       * @description: 加载卫星数据并计算卫星的当前位置和速度，以便在地图上显示卫星的实时位置
       * @return {*}
       */
    loadSatelliteData (jsonName) {
      // 显示加载提示
      document.getElementById('loadingOverlay').style.display = 'block'
      fetch(`json/${jsonName}.json`)
        .then((res) => res.json())
        .then((data) => {
          satelliteObj = {}
          for (const key in data) {
            if (Object.prototype.hasOwnProperty.call(data, key)) {
              const element = data[key]
              const satrec = twoline2satrec(
                element.tle[0],
                element.tle[1]
              )
              // 存储卫星信息
              satelliteObj[key] = {
                id: key,
                name: key,
                country: element.country,
                role: element.role,
                networkSystem: element.networkSystem,
                type: element.type,
                networkState: element.networkState,
                times: [],
                positions: [],
                toSatellitePolyLines: element.toSatellitePolyLines,
                toRadarPolyLines: element.toRadarPolyLines
              }
              let longitude, latitude, height
              for (
                let index = min;
                index <= nowTime;
                index = index + interval
              ) {
                const positionAndVelocity = propagate(
                  satrec,
                  new Date(index)
                )
                // 获取地心惯性坐标
                const positionEci = positionAndVelocity.position
                const gmst = gstime(new Date(index))
                // 转换为大地坐标（经纬高）
                const positionGd = eciToGeodetic(positionEci, gmst)
                longitude = positionGd.longitude
                latitude = positionGd.latitude
                height = positionGd.height * 1000
                satelliteObj[key].times.push(index)
                satelliteObj[key].positions.push([
                  degreesLong(longitude),
                  degreesLat(latitude),
                  height
                ])
              }
            }
          }
          this.computeCircularFlight(satelliteObj)
          document.getElementById('loadingOverlay').style.display = 'none'
        }).catch(() => {
          // 出错时也隐藏加载提示
          document.getElementById('loadingOverlay').style.display = 'none'
        })
    },

    /**
       * @description: 加载雷达数据
       * @return {*}
       */
    loadRadarData () {
      fetch('json/radar.json')
        .then((res) => res.json())
        .then((data) => {
          // 清除之前的雷达实体
          radars.entities.removeAll()
          radarPoints = data
          data.forEach((i) => {
            this.createRadar(i.id, i.lon, i.lat, i.type, i.toRadarPolyLines)
          })
        })
    },

    /**
       * @description: 修改infoBox的位置
       * @param {*} position
       * @return {*}
       */
    showInfoBox (position) {
      const infoBoxElement = document.querySelector('.cesium-infoBox')
      infoBoxElement.style.top = position.y + 'px'
      infoBoxElement.style.left = position.x + 10 + 'px'
      let isDragging = false // 标记是否正在拖拽
      let initialX = 0 // 初始拖拽位置的X坐标
      let initialY = 0 // 初始拖拽位置的Y坐标
      infoBoxElement.addEventListener('mousedown', function (event) {
        isDragging = true
        initialX = event.clientX - infoBoxElement.offsetLeft
        initialY = event.clientY - infoBoxElement.offsetTop
      })
      document.addEventListener('mousemove', function (event) {
        if (isDragging) {
          let offsetX = event.clientX - initialX
          let offsetY = event.clientY - initialY
          infoBoxElement.style.left = offsetX + 'px'
          infoBoxElement.style.top = offsetY + 'px'
        }
      })
      document.addEventListener('mouseup', function () {
        isDragging = false
      })
    },

    /**
       * @description: 鼠标左键单击事件
       * @return {*}
       */
    left_click () {
      this.handler.setInputAction((movement) => {
        const pickedObject = viewer.scene.pick(movement.position)
        // 判断是否点击了实体
        if (Cesium.defined(pickedObject)) {
          let id = pickedObject.id.id
          console.log(`左击${id}`)
          // 如果点击的是模型，显示infoBox
          this.showInfoBox(movement.position)
          // 判断是否点击了雷达
          let isFocusRadar = radarPoints.find((item) => {
            return item.id === id
          })
          if (!isFocusRadar) {
            return
          }
          console.log(isFocusRadar)
          let newCartesian = Cesium.Cartesian3.fromDegrees(
            isFocusRadar.lon,
            isFocusRadar.lat - 15, // 实体纬度减15度
            1000000 // 在实体上方1000000米
          )
          // 设置相机的新位置
          viewer.camera.flyTo({
            destination: newCartesian,
            orientation: {
              heading: Cesium.Math.toRadians(0.0),
              pitch: Cesium.Math.toRadians(-30.0),
              roll: 0.0
            },
            duration: 2.0
          })
        }
      }, Cesium.ScreenSpaceEventType.LEFT_DOUBLE_CLICK)
    },

    /**
      * @description: 鼠标右键单击事件
      * @return {*}
      */
    right_click () {
      this.handler.setInputAction((movement) => {
        const pickedObject = viewer.scene.pick(movement.position)
        if (Cesium.defined(pickedObject)) {
          let id = pickedObject.id.id
          console.log(`右击${id}`)
          // 判断是否点击了卫星
          let isFocusSatellite = Object.values(satelliteObj).find((item) => { item.id === id })
          // 判断是否点击了星间链路
          let isFocusLine = Object.values(satelliteObj).find((item) =>
            item.toSatellitePolyLines.find((item) => { item.id == id })
          )
        }
      }, Cesium.ScreenSpaceEventType.RIGHT_CLICK)
    },

    /**
       * @description: 计算卫星绕地球飞行
       * @param {object} obj 计算卫星绕地球飞行的参数
       * @param {Boolean} hasLine 是否显示卫星飞行轨迹
       * @return {*}
       */
    computeCircularFlight (obj, hasLine = false) {
      for (const key in obj) {
        if (Object.prototype.hasOwnProperty.call(obj, key)) {
          const element = obj[key]
          // console.log(element, `${key}人造卫星`);
          const property = new Cesium.SampledPositionProperty()
          const length = element.positions?.length
          const positions = []
          let p, t
          for (let index = 0; index < length; index++) {
            p = element.positions[index]
            t = element.times[index]
            property.addSample(
              Cesium.JulianDate.fromDate(new Date(t)),
              Cesium.Cartesian3.fromDegrees(p[0], p[1], p[2])
            )
            positions.push(...element.positions[index])
          }
          // 添加卫星实体
          satellites.entities.add({
            id: key,
            name: key,
            model: {
              uri: satellitesModelMap[element.role],
              minimumPixelSize: this.tabIndex === 0 ? 96 : 32,
              maximumScale: 200000,
              color: new Cesium.Color(1.0, 1.0, 1.0, 1.0)
            },
            country: element.country,
            role: element.role,
            networkSystem: element.networkSystem,
            type: element.type,
            networkState: element.networkState,
            toSatellitePolyLines: element.toSatellitePolyLines,
            toRadarPolyLines: element.toRadarPolyLines,
            position: property,
            orientation: new Cesium.VelocityOrientationProperty(property),
            description: `
        卫星名称：${key}<br/>
        卫星标识：XXX <br/>
        研制单位：XXX <br/>
        模块组成：XXX <br/>
        首次入轨时间：XXX  <br/>
        首次通信时间：XXX `
          })
          if (hasLine) {
            // console.log(positions, property._property._times, `${key}的轨迹点集合`);
            polylines.entities.add({
              id: key,
              polyline: {
                width: 1,
                material: Cesium.Color.BLUE.withAlpha(0.5),
                positions: Cesium.Cartesian3.fromDegreesArrayHeights(
                  positions
                )
              },
              description: `这是${key}的运行轨道`
            })
          }
        }
      }
      viewer.dataSources.add(satellites)
      viewer.dataSources.add(polylines)
      viewer.dataSources.add(connection)
    },

    /**
       * @description: 更新飞线
       * @return {*}
       */
    updateFlyLine () {
      for (const key in showFlyObject) {
        if (Object.prototype.hasOwnProperty.call(showFlyObject, key)) {
          const element = showFlyObject[key]
          if (element.entity === null) {
            element.entity = this.createFlyLine(key)
          }
          element.entity.show = element.show
        }
      }
    },
    /**
       * @description: 更新地线
       * @return {*}
       */
    updateGroundLine () {
      for (const key in showGroundObject) {
        if (Object.prototype.hasOwnProperty.call(showGroundObject, key)) {
          const element = showGroundObject[key]
          if (element.entity === null) {
            element.entity = this.createGroundLine(key)
          }
          element.entity.show = element.show
        }
      }
    },
    /**
       * @description: 创建飞线实体
       * @param {string} id
       * @return {*}
       */
    createFlyLine (id) {
      const linePositions = new Cesium.CallbackProperty(() => {
        return Cesium.Cartesian3.fromDegreesArrayHeights([
          showFlyObject[id].po1.longitude,
          showFlyObject[id].po1.latitude,
          showFlyObject[id].po1.height,
          showFlyObject[id].po2.longitude,
          showFlyObject[id].po2.latitude,
          showFlyObject[id].po2.height
        ])
      }, false)
      const line = connection.entities.add({
        id: id,
        polyline: {
          positions: linePositions,
          width: 2,
          arcType: Cesium.ArcType.NONE,
          material: new Cesium.LineFlowMaterialProperty({
            color: new Cesium.Color(1.0, 1.0, 1.0, 1),
            speed: 5,
            percent: 0.5,
            gradient: 0.5
          })
        },
        description: `
            链路名称：${id}<br/>
            通断状态：${connectionStateMap[showFlyObject[id].state]}<br/>
            链路类型：星间同轨 <br/>
            链路距离：XXX km <br/>
            相位差：XXX μrad(微弧度)<br/>
            轨道高度：XXX km<br/>
            双端终端ID：${id} <br/>
            A/B状态：A <br/>
            通信速率：XXX Mbps/Gbps`
      })
      return line
    },

    /**
       * @description: 创建地线实体
       * @param {string} id
       * @return {*}
       */
    createGroundLine (id) {
      const line = connection.entities.add({
        id: id,
        polyline: {
          positions: new Cesium.CallbackProperty(() => {
            return Cesium.Cartesian3.fromDegreesArrayHeights([
              showGroundObject[id].po1.longitude,
              showGroundObject[id].po1.latitude,
              showGroundObject[id].po1.height,
              showGroundObject[id].po2.longitude,
              showGroundObject[id].po2.latitude,
              showGroundObject[id].po2.height
            ])
          }, false),
          width: 3,
          material: new Cesium.LineFlowMaterialProperty({
            color: showGroundObject[id].state,
            speed: 10,
            percent: 0.5,
            gradient: 0.5
          }),
          clampToGround: true
        },
        description: `这是${id}通信线`
      })
      return line
    },

    /**
       * @description: 创建雷达实体
       * @param {string} id 雷达的ID
       * @param {number} lon 雷达的经度
       * @param {number} lat 雷达的纬度
       * @return {*}
       */
    createRadar (id, lon, lat, type, toRadarPolyLines) {
      radars.entities.add({
        id: id,
        model: {
          uri: radarsModelMap[type],
          minimumPixelSize: 32,
          maximumScale: 10000000
        },
        label: new Cesium.LabelGraphics({
          text: id,
          font: '12px sans-serif',
          fillColor: Cesium.Color.RED,
          style: Cesium.LabelStyle.FILL_AND_OUTLINE, // 添加轮廓以增强可读性
          outlineColor: Cesium.Color.WHITE,
          outlineWidth: 1,
          pixelOffset: new Cesium.Cartesian2(0, 14)
        }),
        position: Cesium.Cartesian3.fromDegrees(lon, lat, 0),
        // description: `这是一个名为${id}的雷达`,
        toRadarPolyLines: toRadarPolyLines
      })
      viewer.dataSources.add(radars)
    },
    /**
       * @description: 通过当前时间戳找到对应时间区间的布尔值
       * @param {*} showIntervals
       * @param {*} timestamp
       * @return {*}
       */
    findBooleanByTimestamp (showIntervals, timestamp) {
      for (let i = 0; i < showIntervals?.length; i++) {
        const interval = showIntervals[i].interval.split('/')
        const startTimestamp = parseInt(interval[0])
        const endTimestamp = parseInt(interval[1])
        if (timestamp >= startTimestamp && timestamp < endTimestamp) {
          return showIntervals[i].boolean
        }
      }
      return null // 如果未找到匹配的区间，则返回null
    },

    /**
       * @description: 通过当前时间戳找到对应时间区间的线的状态
       * @param {*} showIntervals
       * @param {*} timestamp
       * @return {*}
       */
    findStateByTimestamp (showIntervals, timestamp) {
      for (let i = 0; i < showIntervals?.length; i++) {
        const interval = showIntervals[i].interval.split('/')
        const startTimestamp = parseInt(interval[0])
        const endTimestamp = parseInt(interval[1])
        if (timestamp >= startTimestamp && timestamp < endTimestamp) {
          return showIntervals[i].state
        }
      }
      return null // 如果未找到匹配的区间，则返回null
    },
    /**
       * @description: 寻找需要显示的通信线
       * @param {*} polyLines
       * @param {*} itemId
       * @return {*}
       */
    findShowByItemId (polyLines, itemId) {
      const polyLine = polyLines.find(item => item.id === itemId)
      return polyLine ? polyLine.show : null
    },

    /**
       * @description: 计算卫星和雷达之间是否通信
       * @return {*}
       */
    computeSatelliteToRadarRange () {
      this.computeRange(satellites, radars, 'toRadarPolyLines', showFlyObject)
      this.updateFlyLine()
    },

    /**
       * @description: 计算卫星之间是否通信
       * @return {*}
       */
    computeSatellitesRange () {
      this.computeRange(satellites, satellites, 'toSatellitePolyLines', showFlyObject)
      this.updateFlyLine()
    },

    /**
      * @description: 计算雷达之间是否通信
      * @return {*}
      */
    computeRadarsRange () {
      this.computeRange(radars, radars, 'toRadarPolyLines', showGroundObject)
      this.updateGroundLine()
    },
    /**
       * @description: 计算两点之间是否通信
       * @param {*} entities1
       * @param {*} entities2
       * @param {*} polyLinesProperty
       * @param {*} resultObject
       * @return {*}
       */
    computeRange (entities1, entities2, polyLinesProperty, resultObject) {
      entities1.entities.values.forEach((i) => {
        entities2.entities.values.forEach((j) => {
          if (i === j) return
          const po1 = i.position?.getValue(viewer.clock.currentTime)
          const po2 = j.position?.getValue(viewer.clock.currentTime)
          const tamp = JulianDateToTimestamp(viewer.clock.currentTime)
          const show = this.findShowByItemId(i[polyLinesProperty], `${i.id} - ${j.id}`)
          if (!show) return
          const isShow = this.findBooleanByTimestamp(show, tamp)
          const state = this.findStateByTimestamp(show, tamp)
          if (po1 && po2) {
            if (isShow) {
              if (resultObject[`${i.id} - ${j.id}`]) {
                resultObject[`${i.id} - ${j.id}`].show = true
                resultObject[`${i.id} - ${j.id}`].state = state
                resultObject[`${i.id} - ${j.id}`].po1 = degreesFromCartesian(po1)
                resultObject[`${i.id} - ${j.id}`].po2 = degreesFromCartesian(po2)
              } else {
                resultObject[`${i.id} - ${j.id}`] = {
                  entity: null,
                  show: true,
                  state: state,
                  po1: degreesFromCartesian(po1),
                  po2: degreesFromCartesian(po2)
                }
              }
            } else {
              if (resultObject[`${i.id} - ${j.id}`]) { resultObject[`${i.id} - ${j.id}`].show = false }
            }
          }
        })
      })
    },
    /**
       * @description:轨道切换
       * @return {*}
       */
    changeTab (index) {
      this.tabIndex = index
      // 清除之前的卫星数据
      satellites.entities.removeAll()
      polylines.entities.removeAll()
      connection.entities.removeAll()
      // 清空存储卫星通信线路信息的对象
      showFlyObject = {}
      // 重新加载卫星数据
      this.loadSatelliteData(`satellite${index}`)
      // 重新设置摄像机视图
      viewer.scene.camera.setView({
        destination: new Cesium.Cartesian3.fromDegrees(
          116.4074,
          0.9042,
          this.tabIndex === 0 ? 120000000 : 25000000
        ),
        orientation: {}
      })
      // 重新计算和显示卫星通信线路
      this.computeSatelliteToRadarRange()
      this.computeSatellitesRange()
      this.computeRadarsRange()
    }
  }
}
</script>

