import * as Cesium from 'cesium'
/**
 * @description: 时间戳转北京时间
 * @param {*} timestamp
 * @return {*}
 */
export function getYMDHMS (timestamp) {
  let time = new Date(timestamp)
  let year = time.getFullYear()
  const month = (time.getMonth() + 1).toString().padStart(2, '0')
  const date = time.getDate().toString().padStart(2, '0')
  const hours = time.getHours().toString().padStart(2, '0')
  const minute = time.getMinutes().toString().padStart(2, '0')
  const second = time.getSeconds().toString().padStart(2, '0')
  return (
    year + '-' + month + '-' + date + ' ' + hours + ':' + minute + ':' + second
  )
}

/**
 * @description: 时间格式化时分秒
 * @param {*} hours
 * @param {*} minutes
 * @param {*} seconds
 * @return {*}
 */
export function formatTime (hours, minutes, seconds) {
  const pad = (num) => (num < 10 ? '0' : '') + num
  return `${pad(hours)}:${pad(minutes)}:${pad(seconds)}`
}

export function TimeFormatter (time, viewModel) {
  return DateTimeFormatter(time, viewModel, true)
}

/**
 * @description: JulianDate转时间戳
 * @param {*} JulianDate
 * @return {*}
 */
export function JulianDateToTimestamp (julianDate) {
  const seconds = Cesium.JulianDate.secondsDifference(
    julianDate,
    Cesium.JulianDate.fromDate(new Date(0))
  )
  const milliseconds = seconds * 1000
  return milliseconds
}

/**
 * @description: 日期时间格式化英文>中文
 * @param {*} datetime
 * @param {*} viewModel
 * @param {*} ignoreDate 是否忽略日期
 * @return {*}
 */
export function DateTimeFormatter (datetime, viewModel, ignoreDate) {
  let julianDT = new Cesium.JulianDate()
  julianDT = Cesium.JulianDate.addHours(datetime, 8, julianDT)
  let gregorianDT = Cesium.JulianDate.toGregorianDate(julianDT)
  let objDT
  if (ignoreDate) {
    objDT = ''
  } else {
    objDT = new Date(gregorianDT.year, gregorianDT.month - 1, gregorianDT.day)
    objDT =
      gregorianDT.year +
      '年' +
      objDT.toLocaleString('zh-cn', { month: 'short' }) +
      gregorianDT.day +
      '日'
    if (viewModel || gregorianDT.hour + gregorianDT.minute === 0) {
      return objDT
      objDT += ''
    }
  }
  return (
    objDT + formatTime(gregorianDT.hour, gregorianDT.minute, gregorianDT.second)
  )
}

/**
 * @description: 接受一个笛卡尔坐标（cartesian）作为参数，并将其转换为地理坐标（经度、纬度和高度）
 * @param {*} cartesian
 * @return {*}
 */
export function degreesFromCartesian (cartesian) {
  const ellipsoid = Cesium.Ellipsoid.WGS84
  const cartographic = ellipsoid.cartesianToCartographic(cartesian)
  const longitude = Cesium.Math.toDegrees(cartographic.longitude)
  const latitude = Cesium.Math.toDegrees(cartographic.latitude)
  const height = cartographic.height
  return { longitude: longitude, latitude: latitude, height: height }
}

// 获取地址栏数据
export function GetQueryString (name) {
  var reg = new RegExp('(^|&)' + name + '=([^&]*)(&|$)')
  var r = window.location.search.substr(1).match(reg)
  if (r != null) return unescape(r[2])
  return null
}
